function sua_register_user($username, $password) {
    global $wpdb;
    $table_name = $wpdb->prefix . 'sua_users';
    $hashed_password = password_hash($password, PASSWORD_BCRYPT);
    $wpdb->insert($table_name, array('username' => $username, 'password' => $hashed_password));
}

function sua_verify_user($username, $password) {
    global $wpdb;
    $table_name = $wpdb->prefix . 'sua_users';
    $user = $wpdb->get_row($wpdb->prepare("SELECT * FROM $table_name WHERE username = %s", $username));
    if ($user && password_verify($password, $user->password)) {
        return true;
    }
    return false;
}

function sua_create_user_table() {
    global $wpdb;
    $table_name = $wpdb->prefix . 'sua_users';
    $charset_collate = $wpdb->get_charset_collate();

    $sql = "CREATE TABLE $table_name (
        id mediumint(9) NOT NULL AUTO_INCREMENT,
        username tinytext NOT NULL,
        password text NOT NULL,
        PRIMARY KEY  (id)
    ) $charset_collate;";

    require_once(ABSPATH . 'wp-admin/includes/upgrade.php');
    dbDelta($sql);
}

register_activation_hook(__FILE__, 'sua_create_user_table');

function sua_register_form() {
    if ($_SERVER['REQUEST_METHOD'] == 'POST' && isset($_POST['sua_register'])) {
        $username = sanitize_text_field($_POST['username']);
        $password = sanitize_text_field($_POST['password']);
        sua_register_user($username, $password);
        echo 'User registered successfully!';
    }
    echo '<form method="POST">
            <input type="text" name="username" placeholder="Username" required>
            <input type="password" name="password" placeholder="Password" required>
            <input type="submit" name="sua_register" value="Register">
          </form>';
}

function sua_login_form() {
    if ($_SERVER['REQUEST_METHOD'] == 'POST' && isset($_POST['sua_login'])) {
        $username = sanitize_text_field($_POST['username']);
        $password = sanitize_text_field($_POST['password']);
        if (sua_verify_user($username, $password)) {
            echo 'Login successful!';
        } else {
            echo 'Invalid username or password.';
        }
    }
    echo '<form method="POST">
            <input type="text" name="username" placeholder="Username" required>
            <input type="password" name="password" placeholder="Password" required>
            <input type="submit" name="sua_login" value="Login">
          </form>';
}

